import os

print('[STEP 1] Creating DepositEngine.py...')
deposit_code = """class DepositEngine:
    # کیف پول رسمی پروه که TON به آن واریز میشود
    # در محیط Production این مقدار از Environment Variable خوانده میشود
    PROJECT_TON_WALLET = "UQD...YOUR_PROJECT_WALLET_ADDRESS"

    # نرخ تبدیل: 1 TON = 100 NSM_Hard
    EXCHANGE_RATE = 100 

    @staticmethod
    def get_deposit_info(user_id: int) -> dict:
        # کاربر باید آیدی تلگرام خود را در قسمت Comment/Memo تراکنش وارد کند
        return {
            'wallet_address': DepositEngine.PROJECT_TON_WALLET,
            'memo': str(user_id),
            'exchange_rate': DepositEngine.EXCHANGE_RATE,
            'instructions': 'Send TON to the address above. You MUST include your Telegram ID in the Memo/Comment field.'
        }

    @staticmethod
    def calculate_nsm_hard(ton_amount: float) -> int:
        return int(ton_amount * DepositEngine.EXCHANGE_RATE)
"""
os.makedirs('Core/App', exist_ok=True)
with open('Core/App/DepositEngine.py', 'w', encoding='utf-8') as f: f.write(deposit_code)
print('[OK] DepositEngine.py created')

print('[STEP 2] Patching mini_api.py with Deposit & Admin Approve endpoints...')
api_file = 'mini_api.py'
if os.path.exists(api_file):
    with open(api_file, 'r', encoding='utf-8') as f: content = f.read()
    
    if 'from Core.App.DepositEngine import DepositEngine' not in content:
        content = 'from Core.App.DepositEngine import DepositEngine\n' + content

    if '/api/ton/deposit_info' not in content:
        deposit_api = '''
@app.route('/api/ton/deposit_info', methods=['GET'])
def get_deposit_info():
    try:
        uid = int(request.args.get('user_id'))
        if not uid: return jsonify({'error': 'Missing ID'}), 400
        info = DepositEngine.get_deposit_info(uid)
        return jsonify(info)
    except Exception as e: return jsonify({'error': str(e)}), 500

@app.route('/api/admin/approve_deposit', methods=['POST'])
def admin_approve_deposit():
    try:
        data = request.json; key = data.get('admin_key'); uid = data.get('user_id')
        ton_amount = data.get('ton_amount', 0)
        if not AdminEngine.verify_commander(key): return jsonify({'error': 'Unauthorized'}), 403
        if not uid or ton_amount <= 0: return jsonify({'error': 'Invalid data'}), 400
        
        nsm_hard_to_add = DepositEngine.calculate_nsm_hard(ton_amount)
        players_collection.update_one({'user_id': uid}, {'$inc': {'nsm_hard': nsm_hard_to_add}})
        NotificationEngine.add_notification(uid, f'💰 Deposit Confirmed! +{nsm_hard_to_add} NSM_Hard credited.', 'deposit', players_collection)
        return jsonify({'success': True, 'message': f'Added {nsm_hard_to_add} NSM_Hard to user {uid}'})
    except Exception as e: return jsonify({'error': str(e)}), 500
'''
        if 'app.run(host=' in content: content = content.replace('app.run(host=', deposit_api + '\napp.run(host=', 1)

    with open(api_file, 'w', encoding='utf-8') as f: f.write(content)
    print('[OK] API Patched')

print('[STEP 3] Rebuilding Mini App UI with TON Deposit Button...')
html = """<!DOCTYPE html><html lang="fa" dir="rtl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Nasrium</title><script src="https://telegram.org/js/telegram-web-app.js"></script><style>:root{--bg:#0f0f1a;--card:#1a1a2e;--accent:#e94560;--gold:#ffd700;--gem:#00ffff;--nsm:#9d4edd;--ton:#0088cc}body{margin:0;padding:0;background:var(--bg);color:#fff;font-family:Tahoma,sans-serif;height:100vh;display:flex;flex-direction:column;overflow:hidden}.header{text-align:center;padding:15px 20px 10px;display:flex;justify-content:space-between;align-items:center}.header h1{margin:0;color:var(--accent);font-size:1.5em}.notif-bell{position:relative;cursor:pointer;font-size:1.5em}.notif-count{position:absolute;top:-5px;right:-5px;background:var(--accent);color:white;border-radius:50%;width:18px;height:18px;font-size:0.7em;display:flex;align-items:center;justify-content:center}.tab-content{flex:1;overflow-y:auto;padding:20px;padding-bottom:80px}.tab-bar{position:fixed;bottom:0;left:0;width:100%;background:#0a0a12;border-top:1px solid #333;display:flex;z-index:100}.tab-btn{flex:1;background:none;border:none;color:#888;padding:12px 0;cursor:pointer;font-size:0.9em;text-align:center}.tab-btn.active{color:var(--nsm);border-top:2px solid var(--nsm)}.stats-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-bottom:15px}.stat-card{background:var(--card);padding:12px;border-radius:10px;text-align:center}.stat-card .value{font-size:1.4em;font-weight:bold;display:block;margin-top:4px}.stat-card.gold .value{color:var(--gold)}.stat-card.gem .value{color:var(--gem)}.stat-card.nsm .value{color:var(--nsm)}.section{background:var(--card);padding:15px;border-radius:12px;margin-bottom:15px}.section-title{font-size:1.1em;margin-bottom:8px;border-bottom:1px solid #333;padding-bottom:5px;color:#ccc}.btn{background:var(--accent);color:white;border:none;padding:8px 16px;border-radius:8px;cursor:pointer;font-weight:bold;width:100%;margin-top:8px}.btn:active{transform:scale(0.95)}.btn-collect{background:#ffd700;color:#000}.btn-upgrade{background:#9d4edd;width:auto;margin-top:0}.btn-raid{background:var(--accent)}.btn-shield{background:#00ffff;color:#000}.btn-train{background:#ff9800;color:#000}.btn-clan{background:#4caf50}.btn-build{background:#607d8b;color:#fff;width:auto;margin-top:0;font-size:0.85em;padding:6px 12px}.btn-daily{background:linear-gradient(45deg,#ff9800,#ff5722);color:white}.btn-search{background:#673ab7;color:white}.btn-ton{background:var(--ton);color:white}.wallet-badge{padding:4px 10px;border-radius:20px;font-size:0.8em;font-weight:bold}.status-active{background:#00ffff22;color:#00ffff;border:1px solid #00ffff}.status-inactive{background:#e9456022;color:#e94560;border:1px solid #e94560}.chat-input{flex:1;padding:10px;border-radius:8px;border:none;background:#1a1a2e;color:white}.building-row{display:flex;justify-content:space-between;margin-bottom:8px;align-items:center;background:#000;padding:8px;border-radius:8px}.lb-row{display:flex;justify-content:space-between;background:#000;padding:8px;border-radius:8px;margin-bottom:5px;font-size:0.85em}.target-card{background:#000;padding:10px;border-radius:8px;border:1px solid var(--accent);margin-bottom:10px}.clan-chat-box{height:200px;overflow-y:auto;background:#000;padding:8px;border-radius:8px;font-size:0.85em;border:1px solid #333}.msg{margin-bottom:5px;border-bottom:1px solid #1a1a2e;padding-bottom:2px}.chat-log{height:calc(100vh - 180px);overflow-y:auto;margin-bottom:10px;padding:10px;background:#000;border-radius:8px;font-size:0.9em}.chat-input-row{display:flex;gap:10px}.notif-item{background:#000;padding:8px;border-radius:8px;margin-bottom:8px;font-size:0.85em;border-right:3px solid var(--accent)}.deposit-box{background:#000;padding:15px;border-radius:8px;margin-top:10px;border:1px solid var(--ton);font-size:0.9em;word-wrap:break-word}.toast{visibility:hidden;min-width:250px;background-color:#333;color:#fff;text-align:center;border-radius:8px;padding:16px;position:fixed;z-index:200;left:50%;bottom:100px;transform:translateX(-50%);opacity:0;transition:opacity 0.3s}.toast.show{visibility:visible;opacity:1}</style></head><body><div class="header"><h1>🌌 NASRIUM</h1><div class="notif-bell" onclick="switchTab('ai')">🔔<span id="notif-count" class="notif-count" style="display:none">0</span></div></div><div id="tab-base" class="tab-content" style="display:block"><div class="stats-grid"><div class="stat-card gold"><div>💰 Gold</div><span class="value" id="gold-val">...</span></div><div class="stat-card gem"><div>💎 Gems</div><span class="value" id="gem-val">...</span></div><div class="stat-card nsm"><div>🪙 NSM</div><span class="value" id="nsm-val">...</span></div></div><div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:15px;background:var(--card);padding:10px;border-radius:12px"><span>🛡️ <span id="wallet-badge" class="wallet-badge status-inactive">OFFLINE</span></span><span style="color:#ffd700;font-weight:bold"><span id="withdraw-pct">0</span>% Share</span></div><button class="btn btn-daily" onclick="claimDaily()">🎁 Daily Reward</button><button class="btn btn-collect" onclick="collectResources()">⚡ Collect Resources</button><div class="section"><div class="section-title">💎 Buy NSM_Hard (Web3)</div><button class="btn btn-ton" onclick="showDepositInfo()">💎 Deposit TON</button><div id="deposit-info-box" class="deposit-box" style="display:none">Loading deposit address...</div></div><div class="section"><div class="section-title">🏗️ Buildings</div><div class="building-row"><span>⛏️ Gold Mine (Lv <span id="gm-lvl">0</span>)</span><button class="btn btn-build" onclick="upgradeBuilding('gold_mine')">Up</button></div><div class="building-row"><span>💎 Gem Drill (Lv <span id="gd-lvl">0</span>)</span><button class="btn btn-build" onclick="upgradeBuilding('gem_drill')">Up</button></div></div><div class="section"><div class="section-title">🏛️ Nexus Core (Level <span id="th-lvl">1</span>)</div><button class="btn btn-upgrade" onclick="upgradeNexus()">Upgrade</button></div></div><div id="tab-war" class="tab-content" style="display:none"><div class="section"><div class="section-title">⚔️ Prepare Forces</div><div style="display:flex;justify-content:space-between;margin-bottom:10px"><span>Troops: <b id="troop-count" style="color:#ff9800">0</span></span><span>Shield: <b id="shield-status" style="color:#00ffff">OFF</b></span></div><button class="btn btn-train" onclick="trainTroops(5)">⚔️ Train 5 Troops</button><button class="btn btn-shield" onclick="activateShield()">🛡️ Shield (10 NSM_H)</button></div><div class="section"><div class="section-title">🎯 Cyber Raid</div><button class="btn btn-search" onclick="findTarget()">🔍 Find Target</button><div id="target-info" class="target-card" style="display:none"></div><button class="btn btn-raid" id="btn-raid" style="display:none" onclick="executeRaid()">⚔️ ATTACK</button></div><div class="section"><div class="section-title">🏆 Leaderboard</div><div id="leaderboard-box">Loading...</div></div></div><div id="tab-clan" class="tab-content" style="display:none"><div class="section"><div class="section-title">🏴 Syndicate Chat</div><div id="clan-chat-box" class="clan-chat-box">Join a Syndicate first.</div><div class="chat-input-row" style="margin-top:10px"><input type="text" id="clan-msg-input" class="chat-input" placeholder="Message..." style="margin-top:0"><button class="btn btn-clan" style="width:auto;margin-top:0" onclick="sendClanMsg()">Send</button></div></div></div><div id="tab-ai" class="tab-content" style="display:none"><div class="section" style="height:100%;display:flex;flex-direction:column"><div class="section-title">🔔 Notifications</div><div id="notif-box" style="max-height:150px;overflow-y:auto;margin-bottom:15px">Loading...</div><div class="section-title" style="margin-top:10px">🤖 NAXUS AI</div><div class="chat-log" id="chat-log"><div style="color:var(--nsm)">NAXUS: Online. Ask 'rules'.</div></div><div class="chat-input-row"><input type="text" id="chat-input" class="chat-input" placeholder="Ask NAXUS..." onkeypress="if(event.key==='Enter')askNaxus()"><button class="btn" style="width:auto;margin-top:0" onclick="askNaxus()">Send</button></div></div></div><div class="tab-bar"><button class="tab-btn active" onclick="switchTab('base')">🏠 Base</button><button class="tab-btn" onclick="switchTab('war')">⚔️ War</button><button class="tab-btn" onclick="switchTab('clan')">🏴 Clan</button><button class="tab-btn" onclick="switchTab('ai')">🤖 NAXUS</button></div><div id="toast" class="toast"></div><script>const tg=window.Telegram.WebApp;tg.ready();tg.expand();tg.setHeaderColor('#0f0f1a');tg.setBackgroundColor('#0f0f1a');const uid=parseInt(new URLSearchParams(window.location.search).get('uid'));let targetId=null;function switchTab(tab){document.querySelectorAll('.tab-content').forEach(el=>el.style.display='none');document.querySelectorAll('.tab-btn').forEach(el=>el.classList.remove('active'));document.getElementById('tab-'+tab).style.display='block';event.currentTarget.classList.add('active')}function showToast(m){const t=document.getElementById("toast");t.innerText=m;t.className="toast show";setTimeout(()=>t.className=t.className.replace("show",""),3e3)}async function loadProfile(){if(!uid)return;try{const r=await fetch('/api/profile/'+uid);const d=await r.json();if(d.is_banned){document.body.innerHTML='<h1 style="text-align:center;color:red;margin-top:40%">🛑 BANNED</h1>';return}document.getElementById('gold-val').innerText=(d.gold||0).toLocaleString();document.getElementById('gem-val').innerText=(d.gems||0).toLocaleString();document.getElementById('nsm-val').innerText=(d.nsm_soft||0).toFixed(2);const b=document.getElementById('wallet-badge');if(d.wallet_active){b.innerText="ONLINE";b.className="wallet-badge status-active"}else{b.innerText="OFFLINE";b.className="wallet-badge status-inactive"}document.getElementById('withdraw-pct').innerText=d.withdraw_percentage||0;document.getElementById('th-lvl').innerText=d.th_level||1;document.getElementById('troop-count').innerText=d.troops||0;document.getElementById('gm-lvl').innerText=(d.buildings&&d.buildings.gold_mine)||0;document.getElementById('gd-lvl').innerText=(d.buildings&&d.buildings.gem_drill)||0;const shieldTime=d.shield_active_until||0;if(Date.now()/1e3<shieldTime){document.getElementById('shield-status').innerText="ON";document.getElementById('shield-status').style.color="#00ffff"}else{document.getElementById('shield-status').innerText="OFF";document.getElementById('shield-status').style.color="#e94560"}if(d.clan_name){loadClanChat()}}catch(e){}}async function showDepositInfo(){if(!uid)return;const box=document.getElementById('deposit-info-box');if(box.style.display==='block'){box.style.display='none';return}try{const r=await fetch(`/api/ton/deposit_info?user_id=${uid}`);const d=await r.json();box.innerHTML=`<b>Wallet Address:</b><br><span style="color:var(--ton)">${d.wallet_address}</span><br><br><b>Memo (Required!):</b> <span style="color:var(--gold)">${d.memo}</span><br><br><i>Rate: 1 TON = ${d.exchange_rate} NSM_Hard</i><br><small>${d.instructions}</small>`;box.style.display='block'}catch(e){box.innerHTML='Error loading deposit info.'}}async function loadNotifications(){if(!uid)return;try{const r=await fetch('/api/notifications/get',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();const box=document.getElementById('notif-box');box.innerHTML='';let unread=0;if(d.notifications){d.notifications.forEach(n=>{if(!n.read)unread++;const date=new Date(n.time*1000);box.innerHTML+=`<div class="notif-item">${n.message} <i style="color:#aaa;font-size:0.8em">${date.toLocaleTimeString()}</i></div>`});const cnt=document.getElementById('notif-count');if(unread>0){cnt.innerText=unread;cnt.style.display='flex'}else{cnt.style.display='none'}}}catch(e){}}async function findTarget(){if(!uid)return;const r=await fetch('/api/matchmaking/find',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();if(d.success){targetId=d.target_id;document.getElementById('target-info').style.display='block';document.getElementById('target-info').innerHTML=`Target: <b>${d.target_id}</b> | Lvl ${d.target_nexus} | 💰 ${d.target_gold}`;document.getElementById('btn-raid').style.display='block'}else{showToast("❌ "+d.message);document.getElementById('target-info').style.display='none';document.getElementById('btn-raid').style.display='none'}}async function loadLeaderboard(){try{const r=await fetch('/api/leaderboard');const d=await r.json();const box=document.getElementById('leaderboard-box');box.innerHTML='';if(d.leaderboard){d.leaderboard.forEach((p,i)=>{box.innerHTML+=`<div class="lb-row"><span>${i+1}. ID: ${p.user_id}</span><span>Lvl ${p.town_hall_level} | 💰 ${p.gold||0}</span></div>`})}}catch(e){}}async function claimDaily(){if(!uid)return;const r=await fetch('/api/missions/daily',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();if(d.success){showToast("🎁 "+d.message);loadProfile()}else showToast("❌ "+d.message)}async function upgradeBuilding(bType){if(!uid)return;const r=await fetch('/api/upgrade/building',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid,building_type:bType})});const d=await r.json();if(d.success){showToast("🏗️ "+d.message);loadProfile()}else showToast("❌ "+d.message)}async function sendClanMsg(){if(!uid)return;const msg=document.getElementById('clan-msg-input').value;if(!msg)return;await fetch('/api/clan/chat/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid,message:msg})});document.getElementById('clan-msg-input').value='';loadClanChat()}async function loadClanChat(){if(!uid)return;try{const r=await fetch('/api/clan/chat/get',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();const box=document.getElementById('clan-chat-box');box.innerHTML='';if(d.messages){d.messages.forEach(m=>{box.innerHTML+='<div class="msg"><b>'+m.name+'</b>: '+m.message+'</div>'});box.scrollTop=box.scrollHeight}}catch(e){}}async function executeRaid(){if(!uid||!targetId)return;const r=await fetch('/api/raid/attack',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({attacker_id:uid,defender_id:targetId})});const d=await r.json();showToast(d.result+": "+d.message);targetId=null;document.getElementById('target-info').style.display='none';document.getElementById('btn-raid').style.display='none';loadProfile();loadNotifications()}async function activateShield(){if(!uid)return;const r=await fetch('/api/raid/shield',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();if(d.success){showToast("🛡️ "+d.message);loadProfile()}else showToast("❌ "+d.message)}async function trainTroops(amount){if(!uid)return;const r=await fetch('/api/troops/train',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid,amount:amount})});const d=await r.json();if(d.success){showToast("⚔️ "+d.message);loadProfile()}else showToast("❌ "+d.message)}async function upgradeNexus(){if(!uid)return;const r=await fetch('/api/upgrade/nexus',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();if(d.success){showToast("✅ Upgraded!");loadProfile()}else showToast("❌ "+d.message)}async function collectResources(){if(!uid)return;const r=await fetch('/api/collect',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid})});const d=await r.json();if(d.earned_gold!==undefined){showToast("💰 Collected!");loadProfile()}}async function askNaxus(){const input=document.getElementById('chat-input');const query=input.value;if(!query)return;const log=document.getElementById('chat-log');log.innerHTML+='<div style="color:#fff;margin-top:5px">You: '+query+'</div>';input.value='';try{const r=await fetch('/api/nexus/ask',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({user_id:uid,query:query,lang:'en'})});const d=await r.json();log.innerHTML+='<div style="color:var(--nsm);margin-top:5px;white-space:pre-line">NAXUS: '+d.response+'</div>';log.scrollTop=log.scrollHeight}catch(e){}}loadProfile();loadLeaderboard();loadNotifications()</script></body></html>"""
os.makedirs('mini_app', exist_ok=True)
with open('mini_app/index.html', 'w', encoding='utf-8') as f: f.write(html)
print('[OK] UI Rebuilt with TON Deposit')
